import{_ as e,o as a,c as n,a6 as d}from"./chunks/framework.DtxWasON.js";const m=JSON.parse('{"title":"Unification ERC-20 & IBC Tokens","description":"","frontmatter":{},"headers":[],"relativePath":"mainchain/networks/erc20_ibc.md","filePath":"mainchain/networks/erc20_ibc.md"}'),o={name:"mainchain/networks/erc20_ibc.md"};function r(i,t,s,h,c,l){return a(),n("div",null,[...t[0]||(t[0]=[d('<h1 id="unification-erc-20-ibc-tokens" tabindex="-1">Unification ERC-20 &amp; IBC Tokens <a class="header-anchor" href="#unification-erc-20-ibc-tokens" aria-label="Permalink to &quot;Unification ERC-20 &amp; IBC Tokens&quot;">​</a></h1><p>In addition to the native <strong>FUND</strong> coin on Unification MainNet, Unification has a number of ERC-20 and IBC tokens deployed on several networks. Below is an overview of the tokens deployed by Unification and its community members.</p><h2 id="fund" tabindex="-1">FUND <a class="header-anchor" href="#fund" aria-label="Permalink to &quot;FUND&quot;">​</a></h2><p><strong>FUND</strong> is the native coin of Unification <code>mainchain</code> used for staking, Tx fees and BEACON/WrkChain fees. It also has representation on other networks as an ERC-20 token. It can be transferred from <code>mainchain</code> to Ethereum mainnet via IBC and Gravity Bridge. From Ethereum, it can currently also be bridged to Polygon mainnet. The ERC-20 can be traded, and is also a utility token for paying for UNoDE subscriptions.</p><p>It is represented as an ERC-20 Token on the following networks:</p><h4 id="mainnets" tabindex="-1">Mainnets <a class="header-anchor" href="#mainnets" aria-label="Permalink to &quot;Mainnets&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Network</th><th>Contract Address/IBC Denomination</th><th>Symbol</th></tr></thead><tbody><tr><td>Unification MainNet</td><td>Native coin <strong>nund</strong></td><td>nund</td></tr><tr><td>Gravity Bridge</td><td><code>ibc/D157AD8A50DAB0FC4EB95BBE1D9407A590FA2CDEE04C90A76C005089BF76E519</code></td><td>nund</td></tr><tr><td>Ethereum mainnet</td><td><code>0xe9b076b476d8865cdf79d1cf7df420ee397a7f75</code></td><td>FUND</td></tr><tr><td>Polygon mainnet</td><td><code>0x1f0145eaC900d75808510190dFC293A09c7A964F</code></td><td>fxFUND</td></tr><tr><td>Shibarium mainnet</td><td><code>0xaDA0fA1f9A4Ea8513B3b607EFD31792336c09507</code></td><td>FUND</td></tr></tbody></table><h4 id="community-mainnet-deployments" tabindex="-1">Community Mainnet deployments <a class="header-anchor" href="#community-mainnet-deployments" aria-label="Permalink to &quot;Community Mainnet deployments&quot;">​</a></h4><p>Additionally, the community have deployed representations of <strong>FUND</strong> on other networks:</p><table tabindex="0"><thead><tr><th>Network</th><th>Contract Address/IBC Denomination</th><th>Symbol</th></tr></thead><tbody><tr><td>Osmosis mainnet</td><td><code>ibc/608EF5C0CE64FEA097500DB39657BDD36CA708CC5DCC2E250A024B6981DD36BC</code></td><td>nund</td></tr></tbody></table><h4 id="testnets" tabindex="-1">Testnets <a class="header-anchor" href="#testnets" aria-label="Permalink to &quot;Testnets&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Network</th><th>Contract Address/IBC Denomination</th><th>Symbol</th></tr></thead><tbody><tr><td>Sepolia testnet</td><td><code>0xAfE70A1985ebDefbDCaeedba045d66091C38E1B1</code></td><td>FUND</td></tr><tr><td>Shibarium testnet</td><td><code>0x27Ad57c007fa9Ef6BC4D2846f341e316e0445dEe</code></td><td>FUND</td></tr></tbody></table><h2 id="xfund" tabindex="-1">xFUND <a class="header-anchor" href="#xfund" aria-label="Permalink to &quot;xFUND&quot;">​</a></h2><p><strong>xFUND</strong> is a utility token used to pay for services such as OoO and VOR.</p><h4 id="mainnets-1" tabindex="-1">Mainnets <a class="header-anchor" href="#mainnets-1" aria-label="Permalink to &quot;Mainnets&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Network</th><th>Contract Address/IBC Denomination</th><th>Symbol</th></tr></thead><tbody><tr><td>Ethereum mainnet</td><td><code>0x892A6f9dF0147e5f079b0993F486F9acA3c87881</code></td><td>xFUND</td></tr><tr><td>Polygon mainnet</td><td><code>0x77a3840f78e4685afaf9c416b36e6eae6122567b</code></td><td>xFUND</td></tr><tr><td>Shibarium mainnet</td><td><code>0x89dc93C6c12CaE47aCAf4aD9305d7A442C30dBB2</code></td><td>xFUND</td></tr></tbody></table><h4 id="testnets-1" tabindex="-1">Testnets <a class="header-anchor" href="#testnets-1" aria-label="Permalink to &quot;Testnets&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Network</th><th>Contract Address/IBC Denomination</th><th>Symbol</th></tr></thead><tbody><tr><td>Sepolia testnet</td><td><code>0xb07C72acF3D7A5E9dA28C56af6F93862f8cc8196</code></td><td>xFUND</td></tr><tr><td>Shibarium testnet</td><td><code>0x78f022230EaE6E05D8739E83a14b0Cf1D00CfaD5</code></td><td>xFUND</td></tr></tbody></table><h2 id="fundx-supertoken" tabindex="-1">FUNDx (Supertoken) <a class="header-anchor" href="#fundx-supertoken" aria-label="Permalink to &quot;FUNDx (Supertoken)&quot;">​</a></h2><p><strong>FUNDx</strong> is the <a href="https://docs.superfluid.finance/superfluid/protocol-overview/in-depth-overview/super-tokens" target="_blank" rel="noreferrer">Superfluid Supertoken</a>. It is wrapped FUND (1:1), with functionality required for Superfluid subscriptions. Used to pay UNoDE subscriptions in <strong>FUND</strong>.</p><p><strong>Note:</strong> Each Supertoken is a wrapper for the corresponding <strong>FUND</strong> token on its respective network</p><h4 id="mainnets-2" tabindex="-1">Mainnets <a class="header-anchor" href="#mainnets-2" aria-label="Permalink to &quot;Mainnets&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Network</th><th>Contract Address</th><th>Symbol</th></tr></thead><tbody><tr><td>Ethereum mainnet</td><td><code>0x479347DfD0Be56f2a5F7bB1506bFD7AB24d4BA26</code></td><td>FUNDx</td></tr><tr><td>Polygon mainnet</td><td><code>0xf1e073d53AF781966F23B1a3B2D9E67cbbA69B92</code></td><td>fxFUNDx</td></tr></tbody></table><h4 id="testnets-2" tabindex="-1">Testnets <a class="header-anchor" href="#testnets-2" aria-label="Permalink to &quot;Testnets&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Network</th><th>Contract Address</th><th>Symbol</th></tr></thead><tbody><tr><td>Sepolia testnet</td><td><code>0x783fDEAB6951504C4601184587AaFED01511ED24</code></td><td>FUNDx</td></tr></tbody></table>',25)])])}const f=e(o,[["render",r]]);export{m as __pageData,f as default};
